package commands

import (
	"context"
	"errors"
)

type EnrollCourseUsecaseParams struct {
	ctx           context.Context
	userId        string
	courseId      string
	sectionNumber *int
	topicNumber   *int
}

type EnrollCourseUsecase struct {
	courseRepository   CourseRepository
	progressRepository ProgressRepository
}

func NewEnrollCourseUsecase(courseRepo CourseRepository, progressRepo ProgressRepository) EnrollCourseUsecase {
	return EnrollCourseUsecase{
		courseRepository:   courseRepo,
		progressRepository: progressRepo,
	}
}

type CourseRepository interface {
	getCourseByCourseId(ctx context.Context, courseId string) (Course, error)
}

type ProgressRepository interface {
	getProgress(ctx context.Context, userId string, courseId string) (Progress, error)
	save(ctx context.Context, progress *Progress) error
}

type EnrollCourseUsecaseInterface interface {
	execute(params EnrollCourseUsecaseParams) (string, error)
}

var ErrTopicNumberRequireSectionNumber = errors.New("topic number require section number")

func (usecase EnrollCourseUsecase) execute(params EnrollCourseUsecaseParams) (string, error) {
	course, err := usecase.courseRepository.getCourseByCourseId(params.ctx, params.courseId)
	if err != nil {
		return "", err
	}

	progress, err := usecase.progressRepository.getProgress(params.ctx, params.userId, params.courseId)
	if err != nil {
		return "", err
	}

	topicId, err := course.enroll(EnrollNumber{
		SectionNumber: params.sectionNumber,
		TopicNumber:   params.topicNumber,
	}, &progress)
	if err != nil {
		return "", err
	}

	return topicId, usecase.progressRepository.save(params.ctx, &progress)
}

