package commands

import (
	"errors"
	"time"
)

type Topic struct {
	topicId            string
	title              string
	description        string
	prerequisites      string
	knowledge          string
	flow               string
	quiz               string
	completionCriteria string
	number             int
}

type Section struct {
	sectionId   string
	title       string
	description string
	number      int
	topics      []Topic
}

type Author struct {
	authorId string
	name     string
}

type Category struct {
	categoryId string
	name       string
}

type Course struct {
	courseId      string
	title         string
	description   string
	slug          string
	tags          []string
	publishStatus string
	category      Category
	publishedAt   *string
	author        Author
	visibility    string
	sections      []Section
}

type EnrollNumber struct {
	SectionNumber *int
	TopicNumber   *int
}

type ProgressRecord struct {
	userTopicProgressId  string
	courseSectionId      string
	courseSectionTopicId string
	sectionNumber        int
	topicNumber          int
	status               string
	startedAt            string
	completedAt          *string
}

type Progress struct {
	courseId string
	userId   string
	records  []ProgressRecord
}

func (p *Progress) lastTopic() (status string, sectionNumber int, topicNumber int) {
	var maxRecord ProgressRecord = ProgressRecord{sectionNumber: -1, topicNumber: -1, status: "NOT_STARTED"}

	for _, record := range p.records {
		if record.sectionNumber > maxRecord.sectionNumber || (record.sectionNumber == maxRecord.sectionNumber && record.topicNumber > maxRecord.topicNumber) {
			maxRecord = record
		}
	}

	return maxRecord.status, maxRecord.sectionNumber, maxRecord.topicNumber
}

func (p *Progress) start(section Section, topic Topic) string {
	for _, record := range p.records {
		if record.courseSectionTopicId == topic.topicId && record.courseSectionId == section.sectionId {
			return topic.topicId
		}
	}

	p.records = append(p.records, ProgressRecord{
		courseSectionId:      section.sectionId,
		courseSectionTopicId: topic.topicId,
		sectionNumber:        section.number,
		topicNumber:          topic.number,
		status:               "IN_PROGRESS",
		startedAt:            time.Now().Format(time.RFC3339),
		completedAt:          nil,
	})
	return topic.topicId
}

var ErrEnrollmentNumberIsNotFound = errors.New("enrollment number is not found")

func (course *Course) enroll(enrollNumber EnrollNumber, progress *Progress) (string, error) {
	if enrollNumber.SectionNumber == nil && enrollNumber.TopicNumber != nil {
		return "", ErrTopicNumberRequireSectionNumber
	}

	sectionNumber := 0
	topicNumber := 0

	if enrollNumber.SectionNumber != nil {
		sectionNumber = *enrollNumber.SectionNumber

		if enrollNumber.TopicNumber == nil {
			topicNumber = 0
		} else {
			topicNumber = *enrollNumber.TopicNumber
		}
	} else {
		status, lastSectionNumber, lastTopicNumber := progress.lastTopic()
		if status == "COMPLETED" {
			nextPosition, err := course.nextTopic(TopicPosition{sectionNumber: lastSectionNumber, topicNumber: lastTopicNumber})
			if err != nil {
				return "", ErrEnrollmentNumberIsNotFound
			}
			sectionNumber, topicNumber = nextPosition.sectionNumber, nextPosition.topicNumber
		} else if status == "IN_PROGRESS" {
			sectionNumber = lastSectionNumber
			topicNumber = lastTopicNumber
		} else {
			sectionNumber = 0
			topicNumber = 0
		}
	}

	section, topic, err := course.getTopic(sectionNumber, topicNumber)
	if err != nil {
		return "", ErrEnrollmentNumberIsNotFound
	}

	topicId := progress.start(section, topic)

	return topicId, nil
}

type TopicPosition struct {
	sectionNumber int
	topicNumber   int
}


var ErrTopicPositionOutOfRange = errors.New("topic position is out of range")

func (course *Course) getTopic(sectionNumber int, topicNumber int) (Section, Topic, error) {
	if sectionNumber < 0 || sectionNumber >= len(course.sections) {
		return Section{}, Topic{}, ErrTopicPositionOutOfRange
	}
	section := course.sections[sectionNumber]
	if topicNumber < 0 || topicNumber >= len(section.topics) {
		return Section{}, Topic{}, ErrTopicPositionOutOfRange
	}
	return section, section.topics[topicNumber], nil
}

func (course *Course) nextTopic(currentTopicPosition TopicPosition) (topicPosition TopicPosition, err error) {
	if currentTopicPosition.sectionNumber < 0 || currentTopicPosition.sectionNumber >= len(course.sections) {
		return TopicPosition{}, ErrTopicPositionOutOfRange
	}

	section := course.sections[currentTopicPosition.sectionNumber]
	if currentTopicPosition.topicNumber < 0 || currentTopicPosition.topicNumber >= len(section.topics) {
		return TopicPosition{}, ErrTopicPositionOutOfRange
	}

	if currentTopicPosition.topicNumber == len(section.topics)-1 {
		if currentTopicPosition.sectionNumber == len(course.sections)-1 {
			return TopicPosition{}, ErrTopicPositionOutOfRange
		}
		return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber + 1, topicNumber: 0}, nil
	}

	return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber, topicNumber: currentTopicPosition.topicNumber + 1}, nil
}

package commands

import (
	"encoding/json"
	"log"
	"net/http"
	"regexp"

	"github.com/harusame0616/ijuku/apps/api/lib/validation"
)

var uuidRegex = regexp.MustCompile(`^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$`)

type Handler struct {
	usecase EnrollCourseUsecaseInterface
}

func NewHandler(usecase EnrollCourseUsecaseInterface) *Handler {
	return &Handler{usecase: usecase}
}

func (h *Handler) PostEnrollmentHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	courseId := r.PathValue("courseId")

	if courseId == "" {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "courseId must be required"})
		return
	}

	if !uuidRegex.MatchString(courseId) {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "courseId must be UUID format"})
		return
	}

	// TODO: 本来は API キーから userId を解決するべきだが、認証機能未実装のため暫定的に body から取得している
	var enrollmentBodyParams struct {
		UserId        string `json:"userId"`
		SectionNumber *int   `json:"sectionNumber"`
		TopicNumber   *int   `json:"topicNumber"`
	}

	defer r.Body.Close()
	if err := json.NewDecoder(r.Body).Decode(&enrollmentBodyParams); err != nil {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "body parameter is invalid json format"})
		return
	}

	if enrollmentBodyParams.UserId == "" {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "userId must be required"})
		return
	}

	if !uuidRegex.MatchString(enrollmentBodyParams.UserId) {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "userId must be UUID format"})
		return
	}

	topicId, err := h.usecase.execute(EnrollCourseUsecaseParams{
		ctx:           r.Context(),
		userId:        enrollmentBodyParams.UserId,
		courseId:      courseId,
		sectionNumber: enrollmentBodyParams.SectionNumber,
		topicNumber:   enrollmentBodyParams.TopicNumber,
	})

	if err == ErrTopicNumberRequireSectionNumber {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "topic number require section number"})
		return
	}

	if err == ErrEnrollmentNumberIsNotFound {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "enrollment number is not found"})
		return
	}

	if err != nil {
		log.Printf("PostEnrollmentHandler error: %v", err)
		w.WriteHeader(http.StatusInternalServerError)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": "INTERNAL_SERVER_ERROR", "message": "internal server error"})
		return
	}

	w.WriteHeader(http.StatusCreated)
	_ = json.NewEncoder(w).Encode(map[string]string{"topicId": topicId})
}

