	_, _ = pool.Exec(ctx, `DELETE FROM categories WHERE category_id = $1`, enrollTestCategoryID)
}

func cleanupProgresses(ctx context.Context, pool *pgxpool.Pool) {
	_, _ = pool.Exec(ctx, `DELETE FROM user_topic_progresses WHERE user_id = $1`, enrollTestUserID)
}

type progressRecord struct {
	topicID string
	status  string
}

func getProgresses(t *testing.T, ctx context.Context, pool *pgxpool.Pool) []progressRecord {
	t.Helper()
	rows, err := pool.Query(ctx,
		`SELECT course_section_topic_id, status FROM user_topic_progresses WHERE user_id = $1 ORDER BY course_section_topic_id`,
		enrollTestUserID,
	)
	if err != nil {
		t.Fatalf("progressの取得に失敗しました: %v", err)
	}
	defer rows.Close()

	var records []progressRecord
	for rows.Next() {
		var r progressRecord
		if err := rows.Scan(&r.topicID, &r.status); err != nil {
			t.Fatalf("progressのスキャンに失敗しました: %v", err)
		}
		records = append(records, r)
	}
	return records
}

func insertProgress(ctx context.Context, pool *pgxpool.Pool, sectionID, topicID, status string) error {
	_, err := pool.Exec(ctx,
		`INSERT INTO user_topic_progresses (user_topic_progress_id, course_id, course_section_id, course_section_topic_id, user_id, status)
		 VALUES (gen_random_uuid(), $1, $2, $3, $4, $5)`,
		enrollTestCourseID, sectionID, topicID, enrollTestUserID, status,
	)
	return err
}

